export const meta = {
  name: 'docs-restructure-audit',
  description: 'Audit every doc/md in cs7980-guide-mate against actual code, then design a restructure + removal plan',
  phases: [
    { title: 'Audit', detail: 'parallel: assess each doc + repo hygiene + code ground-truth' },
    { title: 'Synthesize', detail: 'design new structure + per-file disposition' },
    { title: 'Critique', detail: 'adversarially check nothing important is dropped' },
    { title: 'Revise', detail: 'fold critique into final proposal' },
  ],
}

const ROOT = '/home/ubuntu/cs7980-guide-mate'

const CODE_INVENTORY = `
ACTUAL CODE/CONFIG ON DISK (ground truth as of this audit):
ROS2 package src/guide_mate_explorer/:
  nodes: bfs_explorer.py, glass_guard.py, depth_lidar_fusion.py, combined_node.py(UNTRACKED/new)
  launch: autonomous_mapping.launch.py, depth_lidar_fusion.launch.py, depth_perception.launch.py, explore.launch.py, combined.launch.py(UNTRACKED/new)
  config: nav2_glass.yaml, oakd_mapping.yaml, slam_fused.yaml(UNTRACKED-ish/new)
NEW untracked C++ package src/guide_mate_perception/:
  src/depth_lidar_fusion_node.cpp, CMakeLists.txt, package.xml, launch/depth_lidar_fusion_cpp.launch.py
rviz/: launch_rviz.sh, turtlebot468_mapping.rviz (tracked)
Root: README.md, CLAUDE.md, .gitignore (tracked); start.sh (gitignored)
Vendored third-party clone (gitignored, untracked, on-disk only): aws-iot-device-sdk-python-v2/ (full AWS SDK repo with its own .git, ~20 markdowns)
On-disk credentials (gitignored, never committed): Turtlebot-468.cert.pem, Turtlebot-468.private.key, Turtlebot-468.public.key, Turtlebot-468-Policy, root-CA.crt, c9109663-*AccessToken.txt, connect_device_package.zip
`

const DOC_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    path: { type: 'string' },
    purpose: { type: 'string', description: 'one-line: what this doc is for' },
    summary: { type: 'string', description: '2-4 sentences on actual content' },
    importance: { type: 'string', enum: ['critical', 'useful', 'marginal', 'obsolete'] },
    audience: { type: 'string', description: 'who needs this: team-onboarding / future-self / external / nobody' },
    freshness: { type: 'string', description: 'does it match the actual code/config inventory? note staleness' },
    contradictions: { type: 'array', items: { type: 'string' }, description: 'specific claims that conflict with code/CLAUDE.md/other docs' },
    redundancy: { type: 'array', items: { type: 'string' }, description: 'other doc paths this overlaps/duplicates' },
    qualityIssues: { type: 'array', items: { type: 'string' } },
    uniqueValue: { type: 'string', description: 'what would be LOST if this file were deleted (be concrete)' },
    recommendation: { type: 'string', enum: ['keep', 'trim', 'merge', 'move', 'rename', 'delete'] },
    recommendationDetail: { type: 'string', description: 'if merge/move/rename: into what / where' },
  },
  required: ['path', 'purpose', 'importance', 'freshness', 'redundancy', 'uniqueValue', 'recommendation', 'recommendationDetail'],
}

const HYGIENE_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          item: { type: 'string' },
          observation: { type: 'string' },
          severity: { type: 'string', enum: ['high', 'medium', 'low'] },
          recommendation: { type: 'string' },
        },
        required: ['item', 'observation', 'severity', 'recommendation'],
      },
    },
  },
  required: ['findings'],
}

const docs = [
  { path: 'CLAUDE.md', hint: 'root agent/onboarding guide for the whole repo' },
  { path: 'README.md', hint: 'root repo README' },
  { path: 'docs/README.md', hint: 'docs index + security note' },
  { path: 'docs/aws-iot/README.md', hint: 'aws-iot section index' },
  { path: 'docs/aws-iot/iot-core-overview.md', hint: 'IoT Core thing/policy/endpoint' },
  { path: 'docs/aws-iot/secure-tunneling.md', hint: 'secure tunnel / localproxy' },
  { path: 'docs/aws-iot/service-integration.md', hint: 'IoT service integration' },
  { path: 'docs/camera/README.md', hint: 'camera section index' },
  { path: 'docs/camera/oak-d-camera-test.md', hint: 'OAK-D bring-up/test' },
  { path: 'docs/mapping/README.md', hint: 'mapping section index' },
  { path: 'docs/mapping/depth-perception.md', hint: 'depth/glass fusion writeup' },
  { path: 'docs/mapping/rviz-visualization.md', hint: 'rviz config for mapping' },
  { path: 'docs/network/README.md', hint: 'network section index' },
  { path: 'docs/network/nuwave-connection.md', hint: 'NUwave wifi connection' },
  { path: 'docs/network/ros2-over-nuwave.md', hint: 'ROS2 over NUwave' },
  { path: 'docs/power/README.md', hint: 'power section index' },
  { path: 'docs/power/power-saving.md', hint: 'power saving / park' },
]

phase('Audit')
const auditThunks = docs.map(d => () =>
  agent(
    `You are auditing ONE documentation file in a ROS2 robotics project (TurtleBot 4 autonomous "guide robot").
Read these files: ${ROOT}/${d.path} (the target), and ${ROOT}/CLAUDE.md (project context). If the doc makes claims about code/launch/config, spot-check against the real files under ${ROOT}/src/.
Topic hint: ${d.hint}.
${CODE_INVENTORY}
Assess the target doc honestly and critically. importance: 'critical'=needed to operate/understand the robot or repo; 'useful'=helpful reference; 'marginal'=nice-to-have/thin; 'obsolete'=stale/superseded/empty-stub. Many tiny section-index README.md files may be 'marginal' boilerplate. Flag any factual drift from the actual code inventory. Be specific in uniqueValue about what is irreplaceably documented here (real hardware findings, IPs, gotchas) vs. generic restatement.`,
    { label: `audit:${d.path}`, phase: 'Audit', schema: DOC_SCHEMA }
  )
)
const hygieneThunk = () =>
  agent(
    `You are auditing REPO HYGIENE & STRUCTURE (not doc prose) for ${ROOT}, a ROS2 colcon workspace that also holds project docs.
${CODE_INVENTORY}
Read ${ROOT}/CLAUDE.md and ${ROOT}/.gitignore and list ${ROOT} (top level). Evaluate, as findings:
- The vendored aws-iot-device-sdk-python-v2/ clone (gitignored, on-disk only, ~full SDK with own .git): is keeping it on disk justified, should it be removed/replaced with a pointer/pinned reference, does it bloat the working tree?
- On-disk credentials (gitignored, never committed): clutter in working tree, any residual risk, should they live elsewhere.
- Loose root files: start.sh (gitignored), rviz/ scripts (tracked).
- src/guide_mate_perception/ NEW untracked C++ package + combined_node.py/combined.launch.py/slam_fused.yaml untracked: these are NOT reflected in CLAUDE.md. Is CLAUDE.md drifting from reality?
- Directory layout: is docs/ over-fragmented (many one-file subdirs each with a thin README)? colcon workspace conventions.
Give actionable findings with severity.`,
    { label: 'audit:repo-hygiene', phase: 'Audit', schema: HYGIENE_SCHEMA }
  )
const codeRealityThunk = () =>
  agent(
    `Establish GROUND TRUTH of what the ROS2 code actually provides, to check doc accuracy. Read the node files under ${ROOT}/src/guide_mate_explorer/guide_mate_explorer/ (bfs_explorer.py, glass_guard.py, depth_lidar_fusion.py, combined_node.py) and the launch files, plus skim ${ROOT}/src/guide_mate_perception/src/depth_lidar_fusion_node.cpp and CMakeLists.txt.
${CODE_INVENTORY}
Report: (1) what each node/launch/config actually does in one line; (2) what the NEW untracked combined_node + guide_mate_perception C++ package add (is the C++ a reimplementation of the Python depth_lidar_fusion? is combined_node merging nodes?); (3) concrete discrepancies between the code and CLAUDE.md's description; (4) which DOCS would be the natural home to document the new code. Return prose, organized with clear headers.`,
    { label: 'audit:code-reality', phase: 'Audit' }
  )

const auditResults = await parallel([...auditThunks, hygieneThunk, codeRealityThunk])
const docAudits = auditResults.slice(0, docs.length).filter(Boolean)
const hygiene = auditResults[docs.length]
const codeReality = auditResults[docs.length + 1]

phase('Synthesize')
const SYNTH_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    diagnosis: { type: 'string', description: 'concise overall diagnosis of the current doc/repo state' },
    proposedTree: { type: 'string', description: 'the proposed docs/ + repo top-level layout as an ASCII tree, with brief inline notes' },
    dispositions: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          path: { type: 'string' },
          action: { type: 'string', enum: ['keep', 'trim', 'merge', 'move', 'rename', 'delete', 'create', 'update'] },
          target: { type: 'string', description: 'destination/merge target if applicable, else ""' },
          rationale: { type: 'string' },
        },
        required: ['path', 'action', 'target', 'rationale'],
      },
    },
    onDiskCleanup: { type: 'array', items: { type: 'string' }, description: 'non-git on-disk clutter to remove/relocate and why' },
    keyDecisions: { type: 'array', items: { type: 'string' }, description: 'the few decisions the user must approve' },
    risks: { type: 'array', items: { type: 'string' } },
  },
  required: ['diagnosis', 'proposedTree', 'dispositions', 'onDiskCleanup', 'keyDecisions', 'risks'],
}

const synthPrompt = `You are a documentation architect. Design a clean, properly-structured documentation + repo layout for cs7980-guide-mate (a TurtleBot 4 autonomous guide-robot project; repo IS a ROS2 colcon workspace holding both docs/ and code).
${CODE_INVENTORY}

Per-doc audits (JSON):
${JSON.stringify(docAudits, null, 2)}

Repo hygiene findings (JSON):
${JSON.stringify(hygiene, null, 2)}

Code ground-truth:
${codeReality}

Goals from the user: "we have so many docs and mds and material in this repo. analyze it all and rethink a proper structured way to do this, and remove non-important stuff."

Design principles: prefer a small number of strong, well-organized docs over many thin fragmented ones; collapse one-file subdirectories and boilerplate section-index READMEs unless they earn their place; eliminate redundancy; keep every irreplaceable hardware finding / IP / gotcha (relocate, never lose); keep CLAUDE.md authoritative and in sync with actual code; respect that this is a colcon workspace. Be decisive and concrete. For EVERY existing tracked doc give a disposition. Propose where the new untracked code should be documented. Note on-disk (non-git) cleanup separately (vendored SDK, creds, start.sh).`

const proposal = await agent(synthPrompt, { label: 'synthesize:proposal', phase: 'Synthesize', schema: SYNTH_SCHEMA })

phase('Critique')
const CRIT_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    droppedValue: { type: 'array', items: { type: 'string' }, description: 'anything irreplaceable that the proposal deletes/merges-away without preserving' },
    structureProblems: { type: 'array', items: { type: 'string' } },
    overreach: { type: 'array', items: { type: 'string' }, description: 'proposed deletions/merges that are too aggressive' },
    underreach: { type: 'array', items: { type: 'string' }, description: 'clutter the proposal leaves in place that should be addressed' },
    missingDispositions: { type: 'array', items: { type: 'string' } },
    verdict: { type: 'string', enum: ['sound', 'needs-revision'] },
  },
  required: ['droppedValue', 'structureProblems', 'overreach', 'underreach', 'missingDispositions', 'verdict'],
}
const critique = await agent(
  `Adversarially review this docs-restructure proposal. Your job is to catch: irreplaceable content being silently dropped, over-aggressive deletions, a structure that's worse/awkward, clutter left unaddressed, and any tracked doc lacking a disposition. Default to skepticism.

Proposal (JSON):
${JSON.stringify(proposal, null, 2)}

Original per-doc audits (JSON):
${JSON.stringify(docAudits, null, 2)}

Tracked docs that MUST each have a disposition: ${docs.map(d => d.path).join(', ')}.`,
  { label: 'critique:proposal', phase: 'Critique', schema: CRIT_SCHEMA, effort: 'high' }
)

phase('Revise')
const final = await agent(
  `Produce the FINAL documentation-restructure plan as polished markdown, ready to show the repo owner. Incorporate the critique: preserve everything flagged as irreplaceable, dial back any overreach, address any underreach, fill missing dispositions.

Draft proposal (JSON):
${JSON.stringify(proposal, null, 2)}

Critique to incorporate (JSON):
${JSON.stringify(critique, null, 2)}

Output well-structured markdown with these sections:
## Diagnosis (what's wrong today, concise)
## Proposed structure (ASCII tree of the new docs/ + repo top-level, with one-line notes)
## Per-file plan (a table: File | Action | Destination | Why — cover EVERY tracked doc)
## On-disk cleanup (non-git clutter: vendored SDK, credentials, start.sh — what to do)
## CLAUDE.md sync (specific edits needed so it matches current code: new combined_node, guide_mate_perception C++ pkg, slam_fused.yaml)
## Decisions needed from you (the handful of choices to approve before I execute)
## Risks / what's preserved
Be concrete and decisive. This plan will be executed after approval, so make actions unambiguous.`,
  { label: 'revise:final-plan', phase: 'Revise', effort: 'high' }
)

return { final, critique, proposalDiagnosis: proposal.diagnosis }

